import { Component, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from '../core/services/auth.service';

interface NavItem {
  label: string;
  icon: string;
  path: string;
}

/**
 * LearnLoop authenticated shell: brand header, role-aware navigation
 * (desktop sidebar + mobile bottom tab bar) and logout.
 * Renders the literal "LearnLoop" brand (smoke marker).
 */
@Component({
  selector: 'app-layout',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: './layout.component.html',
  styleUrl: './layout.component.css',
})
export class LayoutComponent {
  readonly brand = 'LearnLoop';

  private readonly studentNav: NavItem[] = [
    { label: 'Catalog', icon: '📚', path: '/catalog' },
    { label: 'My Courses', icon: '🎓', path: '/my-courses' },
  ];

  private readonly instructorNav: NavItem[] = [
    { label: 'Courses', icon: '📚', path: '/instructor/courses' },
    { label: 'Settings', icon: '⚙️', path: '/admin/settings' },
  ];

  readonly user = this.auth.user;
  readonly nav = computed<NavItem[]>(() =>
    this.auth.isInstructor() ? this.instructorNav : this.studentNav,
  );
  readonly roleLabel = computed(() => (this.auth.isInstructor() ? 'Instructor' : 'Student'));
  readonly initials = computed(() => {
    const u = this.auth.user();
    const src = u?.name || u?.email || '?';
    return src.trim().slice(0, 1).toUpperCase();
  });

  constructor(private auth: AuthService) {}

  logout(): void {
    this.auth.logout();
  }
}
